// Check whether Meta social generation is enabled before running.
// Reads ENABLE_META_INSTAGRAM and ENABLE_META_FACEBOOK from n8n Variables.
// If both platforms are disabled, skip generation entirely.
const enableInstagram = ($vars.ENABLE_META_INSTAGRAM || '').toLowerCase() === 'true';
const enableFacebook  = ($vars.ENABLE_META_FACEBOOK  || '').toLowerCase() === 'true';

if (!enableInstagram && !enableFacebook) {
  // Return a sentinel item so the workflow can short-circuit cleanly
  return [{ json: { _meta_skip: true, reason: 'All Meta platforms disabled' } }];
}

const ctx = $input.first().json;

if (!ctx.topic_slug || !ctx.date_key) {
  throw new Error('Missing topic_slug or date_key in input context');
}

if (!ctx.summary) {
  throw new Error(`No summary found in context for ${ctx.topic_slug}/${ctx.date_key}`);
}

return [{
  json: {
    ...ctx,
    _meta_enable_instagram: enableInstagram,
    _meta_enable_facebook:  enableFacebook,
    _meta_skip: false
  }
}];

// Build the AI prompt for Meta social post generation from the daily summary.
const ctx = $input.first().json;
const summary = ctx.summary;

const topicEmoji = {
  crypto:     '🪙',
  finance:    '📈',
  economy:    '🏦',
  health:     '🏥',
  ai:         '🤖',
  energy:     '⚡',
  technology: '💻'
};
const emoji = topicEmoji[ctx.topic_slug] || '📰';

// Build key events summary for prompt context (top 3)
const keyEventsText = (summary.key_events || []).slice(0, 3)
  .map((e, i) => `${i + 1}. ${e.title}: ${e.significance}`)
  .join('\n');

const systemPrompt = `You are a social media content writer for a professional financial intelligence platform. Generate engaging, factual Instagram and Facebook posts from daily topic summaries. Always produce structured JSON output exactly matching the specified schema. Keep language professional but accessible. No clickbait or sensationalism.`;

const userPrompt = `Generate a Meta social post for the following daily summary.

Topic: ${ctx.topic_slug} ${emoji}
Date: ${ctx.date_key}
Headline: ${summary.headline}
Sentiment: ${summary.sentiment}
Topic Score: ${summary.topic_score}/100

Overview:
${summary.overview}

Key Events:
${keyEventsText}

Return a JSON object with these exact fields:
- post_caption (string, 150–500 chars): Engaging feed caption for Instagram and Facebook. Factual. No hashtags in caption body.
- hashtags (array of strings, 8–20 items): Relevant hashtags including # prefix. Mix broad topic tags and specific event tags.
- image_prompt (string, 30–300 chars): Guidance for generating or selecting a background image. Describe visual mood and style.
- story_caption (string, 40–150 chars): Short punchy caption for the story format.
- story_background_hint (string, 20–150 chars): Visual hint for story background style.
- cta (string or null, max 120 chars): Optional call-to-action. Use 'Full daily ${ctx.topic_slug} briefing — link in bio.' or null.

Respond with valid JSON only. No markdown fences.`;

return [{
  json: {
    ...ctx,
    _prompt_system: systemPrompt,
    _prompt_user:   userPrompt
  }
}];

// Parse and validate the AI JSON output.
// Required fields: post_caption, hashtags, image_prompt
const ctx = $('Build AI Prompt').item.json;
const rawText = $input.item.json?.message?.content
             || $input.item.json?.choices?.[0]?.message?.content
             || $input.item.json?.text
             || '';

let parsed;
try {
  // Strip markdown fences if present
  const cleaned = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Meta social AI output is not valid JSON: ${e.message}. Raw: ${rawText.slice(0, 300)}`);
}

// Required field validation
const required = ['post_caption', 'hashtags', 'image_prompt'];
for (const field of required) {
  if (!parsed[field]) {
    throw new Error(`Meta social AI output missing required field: ${field}`);
  }
}

if (!Array.isArray(parsed.hashtags) || parsed.hashtags.length < 3) {
  throw new Error(`Meta social AI output hashtags must be an array with at least 3 items`);
}

// Clamp post_caption to 2000 chars (schema max)
if (typeof parsed.post_caption === 'string' && parsed.post_caption.length > 2000) {
  parsed.post_caption = parsed.post_caption.slice(0, 1997) + '...';
}

// Clamp story_caption to 200 chars
if (typeof parsed.story_caption === 'string' && parsed.story_caption.length > 200) {
  parsed.story_caption = parsed.story_caption.slice(0, 197) + '...';
}

// Ensure hashtags have # prefix
parsed.hashtags = parsed.hashtags.map(h =>
  typeof h === 'string' ? (h.startsWith('#') ? h : '#' + h) : h
);

return [{ json: { ...ctx, _ai_output: parsed } }];

// Apply platform-specific formatting to produce the meta_social_asset contract.
// Instagram: caption max 2200 chars, hashtags at end
// Facebook: caption max 63206 chars, hashtags at end

const ctx = $input.first().json;
const ai  = ctx._ai_output;

// Retrieve base topic hashtags from config (hardcoded here for workflow portability)
const topicBaseHashtags = {
  crypto:     ['#crypto', '#blockchain', '#digitalassets', '#web3'],
  finance:    ['#finance', '#investing', '#markets', '#stocks'],
  economy:    ['#economy', '#macroeconomics', '#fed', '#inflation'],
  health:     ['#health', '#wellness', '#medicine', '#healthcare'],
  ai:         ['#AI', '#artificialintelligence', '#machinelearning', '#tech'],
  energy:     ['#energy', '#renewableenergy', '#oilandgas', '#cleanenergy'],
  technology: ['#technology', '#tech', '#innovation', '#software']
};

// Merge AI hashtags with topic base hashtags (deduplicate)
const baseHashtags = topicBaseHashtags[ctx.topic_slug] || [];
const allHashtags = [...new Set([...ai.hashtags, ...baseHashtags])].slice(0, 30);
const hashtagLine = allHashtags.join(' ');

// CTA line
const ctaText = ai.cta || `Follow for daily ${ctx.topic_slug} updates.`;

// Build full caption body (shared base)
const captionBody = ai.post_caption.trim();

// Instagram caption: caption body + CTA + hashtags, max 2200 chars
function buildInstagramCaption(body, cta, hashtags) {
  const ctaBlock   = cta ? '\n\n' + cta : '';
  const hashBlock  = '\n\n' + hashtags;
  const full = body + ctaBlock + hashBlock;
  if (full.length <= 2200) return full;
  // Trim caption body to fit within 2200
  const overhead = ctaBlock.length + hashBlock.length;
  const trimmed  = body.slice(0, 2200 - overhead - 4) + '...';
  return trimmed + ctaBlock + hashBlock;
}

// Facebook caption: same structure, higher limit (63206)
function buildFacebookCaption(body, cta, hashtags) {
  const ctaBlock  = cta ? '\n\n' + cta : '';
  const hashBlock = '\n\n' + hashtags;
  const full = body + ctaBlock + hashBlock;
  // Facebook's limit is large enough that truncation is almost never needed
  return full.length <= 63206 ? full : full.slice(0, 63202) + '...';
}

const enableInstagram   = !!ctx._meta_enable_instagram;
const enableFacebook    = !!ctx._meta_enable_facebook;
const enableIgStories   = ($vars.ENABLE_META_INSTAGRAM_STORIES || '').toLowerCase() === 'true';
const enableFbStories   = ($vars.ENABLE_META_FACEBOOK_STORIES  || '').toLowerCase() === 'true';

const asset = {
  topic_slug:     ctx.topic_slug,
  date_key:       ctx.date_key,
  asset_type:     'daily_post',
  source_type:    'daily_summary',
  source_id:      null,
  publish_job_id: ctx.publish_job_id || null,
  ai_output: {
    post_caption:          ai.post_caption,
    hashtags:              ai.hashtags,
    image_prompt:          ai.image_prompt,
    story_caption:         ai.story_caption || null,
    story_background_hint: ai.story_background_hint || null,
    cta:                   ai.cta || null
  },
  instagram: {
    enabled:       enableInstagram,
    caption:       buildInstagramCaption(captionBody, ctaText, hashtagLine),
    story_caption: ai.story_caption || null,
    story_enabled: enableInstagram && enableIgStories
  },
  facebook: {
    enabled:       enableFacebook,
    caption:       buildFacebookCaption(captionBody, ctaText, hashtagLine),
    story_caption: ai.story_caption || null,
    story_enabled: enableFacebook && enableFbStories
  },
  generated_at: new Date().toISOString()
};

return [{ json: asset }];
